     1→// Module: AIAssistant — CortexBuild Ultimate
     2→import { useState, useEffect } from 'react';
     3→import { Send, Bot, Zap, Check, AlertCircle, DollarSign, FileText, BarChart3 } from 'lucide-react';
     4→import clsx from 'clsx';
     5→
     6→interface Message {
     7→  id: string;
     8→  role: 'user' | 'assistant';
     9→  content: string;
    10→  timestamp: Date;
    11→}
    12→
    13→interface Agent {
    14→  id: string;
    15→  name: string;
    16→  icon: React.FC<{ className?: string }>;
    17→  active: boolean;
    18→  lastUsed: string;
    19→}
    20→
    21→export function AIAssistant() {
    22→  const [messages, setMessages] = useState<Message[]>([]);
    23→  const [input, setInput] = useState('');
    24→  const [selectedAgent, setSelectedAgent] = useState<string>('safety');
    25→  const [isTyping, setIsTyping] = useState(false);
    26→
    27→  const agents: Agent[] = [
    28→    { id: 'safety', name: 'Safety Analyser', icon: AlertCircle, active: true, lastUsed: '2 hours ago' },
    29→    { id: 'rfi', name: 'RFI Responder', icon: FileText, active: true, lastUsed: '1 day ago' },
    30→    { id: 'rams', name: 'RAMS Generator', icon: Zap, active: true, lastUsed: '3 days ago' },
    31→    { id: 'report', name: 'Daily Report Agent', icon: BarChart3, active: true, lastUsed: '1 hour ago' },
    32→    { id: 'change', name: 'Change Order Agent', icon: DollarSign, active: true, lastUsed: '5 days ago' },
    33→    { id: 'tender', name: 'Tender Scorer', icon: Check, active: true, lastUsed: '1 week ago' }
    34→  ];
    35→
    36→  const suggestedPrompts = [
    37→    "Analyse this week's safety incidents",
    38→    "Draft response for RFI-CW-042",
    39→    "Generate RAMS for scaffold erection",
    40→    "Summarise Canary Wharf daily report",
    41→    "Calculate CIS deduction for Apex Electrical",
    42→    "What's our current cash position?"
    43→  ];
    44→
    45→  const mockResponses: Record<string, string> = {
    46→    "Analyse this week's safety incidents": "This week has shown a 15% reduction in near-miss incidents compared to the previous week, with the primary concern being fall-from-height risks on elevated work areas. I recommend prioritising working-at-height toolbox talks and conducting secondary inspections of all fall protection equipment. The Canary Wharf site particularly needs attention with 3 near-miss reports.",
    47→    "Draft response for RFI-CW-042": "RFI-CW-042 Structural beam specification — Response: The UC 305×305×198 specification per the structural drawings should take precedence over the earlier notation. The higher capacity design provides necessary safety margins for the anticipated loading patterns and is recommended by the structural engineer. Approval granted to proceed with UC 305 sections.",
    48→    "Generate RAMS for scaffold erection": "RAMS document generated for Scaffold Erection Activity. Key hazards identified: (1) Falls from height — controls: full harness systems, guardrails; (2) Collapse of scaffold — controls: design verification, weekly inspections; (3) Falling objects — controls: safety nets, hard hat zones. Document ready for review by HSE team.",
    49→    "Summarise Canary Wharf daily report": "Canary Wharf Site Summary — Floor 8 steel erection 92% complete. Concrete pour scheduled for Level 7 on schedule. MEP rough-in work progressing well on floors 3-4. No safety incidents. Weather ideal for external works. Weekly target tracking 98% completion.",
    50→    "Calculate CIS deduction for Apex Electrical": "CIS Deduction Calculation (Apex Electrical, March 2026): Gross Payment: £48,500 | Materials: £12,000 | Labour: £36,500 | CIS Rate (Verified): 20% | Deduction: £7,300 | Net Payment: £41,200. Monthly summary and payment advice prepared for submission.",
    51→    "What's our current cash position?": "Current Cash Position (as of 21 March 2026): Invoiced to clients: £588.5K | Paid in: £94.5K | Outstanding: £279.2K (including £67.2K overdue). Recommended actions: Chase overdue invoices on WM Council (£67.2K) and issue escalation notice on disputed invoice from Nordic Logistics."
    52→  };
    53→
    54→  const handleSendMessage = (text?: string) => {
    55→    const messageText = text || input;
    56→    if (!messageText.trim()) return;
    57→
    58→    const userMessage: Message = {
    59→      id: Date.now().toString(),
    60→      role: 'user',
    61→      content: messageText,
    62→      timestamp: new Date()
    63→    };
    64→
    65→    setMessages(prev => [...prev, userMessage]);
    66→    setInput('');
    67→    setIsTyping(true);
    68→
    69→    setTimeout(() => {
    70→      const response: Message = {
    71→        id: (Date.now() + 1).toString(),
    72→        role: 'assistant',
    73→        content: mockResponses[messageText] || `I'll analyse your request regarding "${messageText}". Based on current project data and safety protocols, here are my insights and recommendations for the CortexBuild team.`,
    74→        timestamp: new Date()
    75→      };
    76→      setMessages(prev => [...prev, response]);
    77→      setIsTyping(false);
    78→    }, 1500);
    79→  };
    80→
    81→  return (
    82→    <div className="h-full flex bg-gradient-to-br from-gray-950 via-gray-900 to-gray-950">
    83→      {/* Left Sidebar - Agents */}
    84→      <div className="w-64 border-r border-gray-800 bg-gray-900/50 p-4 overflow-y-auto">
    85→        <h2 className="mb-4 text-xs font-bold uppercase tracking-widest text-gray-500">AI Agents</h2>
    86→        <div className="space-y-2">
    87→          {agents.map(agent => {
    88→            const Icon = agent.icon;
    89→            return (
    90→              <button
    91→                key={agent.id}
    92→                onClick={() => setSelectedAgent(agent.id)}
    93→                className={clsx(
    94→                  'w-full rounded-xl border p-3 text-left transition-all',
    95→                  selectedAgent === agent.id
    96→                    ? 'border-blue-600 bg-blue-900/30'
    97→                    : 'border-gray-800 bg-gray-800/30 hover:bg-gray-800/50'
    98→                )}
    99→              >
   100→                <div className="mb-2 flex items-center gap-2">
   101→                  <Icon className="h-4 w-4 text-blue-400" />
   102→                  <span className="text-sm font-semibold text-white">{agent.name}</span>
   103→                </div>
   104→                <div className="flex items-center justify-between text-xs">
   105→                  <span className="inline-flex items-center gap-1 text-emerald-400">
   106→                    <div className="h-1.5 w-1.5 rounded-full bg-emerald-400" />
   107→                    Active
   108→                  </span>
   109→                  <span className="text-gray-500">{agent.lastUsed}</span>
   110→                </div>
   111→              </button>
   112→            );
   113→          })}
   114→        </div>
   115→      </div>
   116→
   117→      {/* Main Chat Area */}
   118→      <div className="flex-1 flex flex-col">
   119→        {/* Header */}
   120→        <div className="border-b border-gray-800 bg-gradient-to-r from-blue-900/20 to-purple-900/10 px-6 py-4">
   121→          <h1 className="mb-1 text-2xl font-bold text-white">CortexBuild AI</h1>
   122→          <p className="text-xs text-blue-300">Powered by Claude · Advanced Construction Intelligence</p>
   123→        </div>
   124→
   125→        {/* Messages Area */}
   126→        <div className="flex-1 overflow-y-auto p-6 space-y-4">
   127→          {messages.length === 0 ? (
   128→            <div className="flex h-full flex-col items-center justify-center">
   129→              <Zap className="mb-4 h-12 w-12 text-blue-500/50" />
   130→              <h2 className="mb-2 text-xl font-bold text-white">Ask CortexBuild AI</h2>
   131→              <p className="mb-6 text-center text-sm text-gray-400 max-w-md">
   132→                Get instant insights on safety, RFIs, RAMS, reports, and more. Our AI agents are ready to assist.
   133→              </p>
   134→              <div className="grid grid-cols-2 gap-2 w-full max-w-md">
   135→                {suggestedPrompts.map((prompt, idx) => (
   136→                  <button
   137→                    key={idx}
   138→                    onClick={() => handleSendMessage(prompt)}
   139→                    className="rounded-lg border border-gray-700 bg-gray-800/50 px-3 py-2 text-xs text-gray-300 transition hover:border-blue-600 hover:bg-gray-800 hover:text-white"
   140→                  >
   141→                    {prompt}
   142→                  </button>
   143→                ))}
   144→              </div>
   145→            </div>
   146→          ) : (
   147→            <>
   148→              {messages.map(msg => (
   149→                <div key={msg.id} className={clsx('flex gap-3', msg.role === 'user' ? 'justify-end' : 'justify-start')}>
   150→                  {msg.role === 'assistant' && (
   151→                    <div className="flex-shrink-0 h-8 w-8 rounded-full bg-blue-600/20 flex items-center justify-center">
   152→                      <Bot className="h-4 w-4 text-blue-400" />
   153→                    </div>
   154→                  )}
   155→                  <div
   156→                    className={clsx(
   157→                      'max-w-md rounded-xl px-4 py-3 text-sm',
   158→                      msg.role === 'user'
   159→                        ? 'bg-blue-600 text-white'
   160→                        : 'bg-gray-800 text-gray-100 border border-gray-700'
   161→                    )}
   162→                  >
